#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 1e6+5;
LL n,x[N],p[N],c[N],sp[N],spx[N];
LL st,ed,q[N],dp[N],Ans;
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
bool Beg(int i,int j,int k){
    LD dx=sp[i]-sp[j];
    LD dy=dp[i]+spx[i]-dp[j]-spx[j];
    return (dy/dx<=k);
}
bool kpD(int i,int j,int k,int l){
    LD dx=sp[i]-sp[j];
    LD dy=dp[i]+spx[i]-dp[j]-spx[j];
    LD bx=sp[k]-sp[l];
    LD by=dp[k]+spx[k]-dp[l]-spx[l];
    return (dy/dx>=by/bx);
}
int main(){
    n=read();
    for(int i=1;i<=n;i++)
        x[i]=read(),p[i]=read(),c[i]=read(),
        sp[i]=sp[i-1]+p[i],spx[i]=spx[i-1]+p[i]*x[i];
    st=1,ed=1,dp[0]=0,q[1]=0;
    for(int i=1;i<=n;i++){
        while(st<ed&&Beg(q[st],q[st+1],x[i]))st++;
        dp[i]=dp[q[st]]+c[i]+x[i]*(sp[i]-sp[q[st]])-(spx[i]-spx[q[st]]);
        if(!p[i])dp[i]=min(dp[i],dp[i-1]);
        while(st<ed&&kpD(q[ed-1],q[ed],q[ed-1],i))ed--;q[++ed]=i;
    }Ans=dp[n];
    for(int i=n;i&&sp[i]==sp[i-1];Ans=min(Ans,dp[--i]));
    cout<<Ans<<"\n";
    return 0;
}
